const GRID_CLASS = "grid grid-cols-[2.5rem_1rem_1fr] gap-x-3"
const RAIL_LEFT = "calc(2.5rem + 0.75rem + 0.5rem)"

/**
 * Above this many entries the delay-armed intro fades would promote
 * every entry to a compositor layer at once and crash mobile Safari's
 * compositor. Long timelines fade entries in as they enter the
 * viewport during the auto-scroll instead — same look, but only a
 * handful of live animations at any moment.
 */
const MAX_ARMED_ENTRIES = 80

function RailTick() {
  return (
    <span
      aria-hidden="true"
      className="block h-px w-[10px] bg-zinc-400 transition-colors duration-300 dark:bg-zinc-700"
    />
  )
}

/**
 * One event line. Touch layouts have no hover reveal, so an event with
 * attached media becomes tappable: the media expands into the lightbox
 * from the event's text, framed by the poster image's real aspect.
 */
function LifelineVerticalEvent({ event }: { event: LifelineEvent }) {
  const fireworks = useLifelineFireworks()
  const image = getLifelineEventImage(event)
  const effect = getLifelineEventEffect(event)
  const textRef = useRef<HTMLParagraphElement>(null)
  const aspectRef = useRef(3 / 4)
  const [lightboxStart, setLightboxStart] =
    useState<LifelineLightboxStart | null>(null)

  // The event text has no card geometry — synthesize a small seed
  // centered on the text, carrying the media's aspect so the lightbox
  // expands into the right frame.
  const measureText = useCallback((): LifelineLightboxStart | null => {
    const el = textRef.current
    if (!el) return null
    const rect = el.getBoundingClientRect()
    const w = 96
    return {
      cx: rect.left + rect.width / 2,
      cy: rect.top + rect.height / 2,
      w,
      h: w * aspectRef.current,
    }
  }, [])

  const openMedia = () => {
    if (!image || lightboxStart) return
    // The poster sets the frame; for videos it shares the clip's aspect.
    const probe = new window.Image()
    probe.src = image.src
    const open = () => {
      if (probe.naturalWidth > 0) {
        aspectRef.current = probe.naturalHeight / probe.naturalWidth
      }
      setLightboxStart(measureText())
    }
    if (probe.complete) {
      open()
    } else {
      probe.onload = open
      probe.onerror = open
    }
  }

  return (
    <>
      <p
        ref={textRef}
        className={cn(
          "max-w-[18rem] text-left text-[14px] leading-[1.55] tracking-[-0.01em]",
          (image || effect) && "cursor-pointer",
        )}
        onClick={
          image
            ? openMedia
            : effect && fireworks
              ? () => fireworks.launch(effect)
              : undefined
        }
      >
        <LifelineEventText event={event} />
        {image && (
          // Glued to the last word with a no-break space so the icon
          // can never wrap onto a line of its own.
          <span className="whitespace-nowrap">
            {" "}
            {image.video ? (
              <Film
                className="ml-0.5 inline-block h-3 w-3 -translate-y-px text-zinc-400 transition-colors duration-300 dark:text-zinc-600"
                strokeWidth={1.75}
                aria-hidden="true"
              />
            ) : (
              <ImageIcon
                className="ml-0.5 inline-block h-3 w-3 -translate-y-px text-zinc-400 transition-colors duration-300 dark:text-zinc-600"
                strokeWidth={1.75}
                aria-hidden="true"
              />
            )}
          </span>
        )}
      </p>
      {lightboxStart && image && (
        <LifelineLightbox
          photo={image}
          rotate={0}
          start={lightboxStart}
          getHome={measureText}
          onClosed={() => setLightboxStart(null)}
        />
      )}
    </>
  )
}

const LifelineVerticalEntry = forwardRef<
  HTMLLIElement,
  {
    marker: LifelineMarker
    birthYear: number
    animateIntro?: boolean
    introDelay?: number
    introDuration?: number
    revealPending?: boolean
  }
>(function LifelineVerticalEntry(
  {
    marker,
    birthYear,
    animateIntro = false,
    introDelay = 0,
    introDuration = 420,
    revealPending = false,
  },
  ref,
) {
  const age = marker.age ?? marker.year - birthYear
  const people = aggregateLifelinePeople(marker)
  const photos = marker.photos ?? []
  const hasContent = hasMarkerContent(marker) || photos.length > 0
  // Fresh tilts per visit; stacked neighbors lean apart.
  const [photoTilts] = useState(() =>
    (marker.photos ?? []).map((_, index) => {
      const sign =
        (marker.photos?.length ?? 0) > 1
          ? index % 2 === 0
            ? -1
            : 1
          : Math.random() > 0.5
            ? 1
            : -1
      return sign * (2 + Math.random() * 4)
    }),
  )

  return (
    <li
      ref={ref}
      className={hasContent ? "pb-10" : "pb-3"}
      aria-label={marker.label ?? `${marker.year}`}
    >
      <div
        className={cn(
          animateIntro && "lifeline-marker-intro",
          revealPending && "opacity-0",
        )}
        style={{
          animationDelay: animateIntro ? `${introDelay}ms` : undefined,
          ...(animateIntro
            ? ({
                "--lifeline-marker-fade-ms": `${introDuration}ms`,
              } as CSSProperties)
            : {}),
        }}
      >
        <div className={`${GRID_CLASS} items-center`}>
          <p className="text-right text-[11px] font-medium leading-4 tabular-nums text-zinc-500 transition-colors duration-300 dark:text-zinc-600">
            {age}
          </p>

          <div className="flex items-center justify-center">
            <RailTick />
          </div>

          <p className="whitespace-nowrap text-[15px] font-medium leading-5 tabular-nums text-zinc-500 transition-colors duration-300 dark:text-zinc-400">
            {marker.label ?? marker.year}
          </p>
        </div>

        {hasContent && (
          <div className={`${GRID_CLASS} mt-6`}>
            <div aria-hidden="true" />
            <div aria-hidden="true" />
            <div className="min-w-0 text-zinc-500 transition-colors duration-300 dark:text-zinc-400">
              {marker.badges && marker.badges.length > 0 && (
                <div className="mb-3 flex items-center justify-start gap-2">
                  {marker.badges.map((badge) => (
                    // eslint-disable-next-line @next/next/no-img-element
                    <img
                      key={badge.src}
                      src={badge.src}
                      alt={badge.alt}
                      className="h-6 w-6 object-contain opacity-80"
                    />
                  ))}
                </div>
              )}

              {marker.companies && marker.companies.length > 0 && (
                <div className="mb-2 flex items-center justify-start gap-1.5">
                  {marker.companies.map((company) => (
                    <CompanyIcon
                      key={company.id}
                      id={company.id}
                      label={company.name}
                      className="opacity-70"
                    />
                  ))}
                </div>
              )}

              {marker.events.length > 0 && (
                <div className="space-y-4">
                  {marker.events.map((event, index) => (
                    <LifelineVerticalEvent
                      key={getLifelineEventKey(event, index)}
                      event={event}
                    />
                  ))}
                </div>
              )}

              {photos.length > 0 && (
                <div className="mt-6 flex flex-wrap items-start">
                  {photos.map((photo, index) => (
                    <LifelinePhotoCard
                      key={`${photo.src}-${index}`}
                      photo={photo}
                      rotate={photo.rotate ?? photoTilts[index] ?? 0}
                      width={160}
                      className={cn(
                        "relative",
                        index > 0 && "-ml-8 mt-6",
                      )}
                    />
                  ))}
                </div>
              )}

              {people.length > 0 && (
                <div className="mt-6 border-t border-zinc-200/70 pt-5 transition-colors duration-300 dark:border-zinc-800/70">
                  <LifelinePeople people={people} allowWrap />
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </li>
  )
})

export function LifelineVertical({
  markers,
  birthYear,
  title = "Lifeline",
}: LifelineProps) {
  const heights = useMemo(
    () =>
      markers.map((marker, index) =>
        getMarkerHeight(marker, markers[index + 1]?.year),
      ),
    [markers],
  )

  const intro = useLifelineIntro(heights)
  const isIntroAnimating = intro.shouldPlay && intro.isPlaying

  // Warm the event media posters during idle — the tap-to-open
  // lightbox measures its frame from these, and a cold fetch at tap
  // time reads as lag.
  useEffect(() => {
    const sources: string[] = []
    for (const marker of markers) {
      for (const event of marker.events) {
        const image = getLifelineEventImage(event)
        if (image) sources.push(image.src)
      }
    }
    if (sources.length === 0) return

    const warm = () => {
      sources.forEach((src) => {
        const image = new window.Image()
        image.src = src
      })
    }

    if (typeof window.requestIdleCallback === "function") {
      const handle = window.requestIdleCallback(warm)
      return () => window.cancelIdleCallback(handle)
    }
    const timeout = window.setTimeout(warm, 2000)
    return () => window.clearTimeout(timeout)
  }, [markers])

  const { sectionRef, setEntryRef, isLayoutReady } = useLifelineVerticalScroll(
    markers.length,
    {
      introLocked: isIntroAnimating,
      introAnimating: isIntroAnimating,
      introSkipped: !intro.shouldPlay,
      introRailMs: intro.railDuration,
      introGetTrackProgress: intro.getTrackProgressAtTime,
      onIntroScrollStart: intro.startIntroTimer,
      onIntroSettleComplete: intro.completeIntro,
    },
  )

  const showIntro = isIntroAnimating && isLayoutReady
  const revealOnScroll = markers.length > MAX_ARMED_ENTRIES
  const animateEntries = showIntro && !revealOnScroll

  // Rail-synced fades for long timelines: entries render hidden and
  // each one fades in the moment the rail tip (--lifeline-intro-progress,
  // written every frame by the intro scroll) crosses its position —
  // desktop's choreography, but each entry drops its animation (and
  // compositor layer) as soon as its fade finishes.
  useEffect(() => {
    if (!showIntro || !revealOnScroll) return
    const section = sectionRef.current
    const ol = section?.querySelector("ol")
    if (!section || !ol) return

    const entries = Array.from(ol.children) as HTMLElement[]
    const targets = entries.map(
      (li) => li.firstElementChild as HTMLElement | null,
    )

    const onAnimationEnd = (event: AnimationEvent) => {
      if (event.animationName !== "lifeline-marker-in") return
      ;(event.target as HTMLElement).classList.remove("lifeline-marker-intro")
    }
    section.addEventListener("animationend", onAnimationEnd)

    let next = 0
    let frame = 0
    const tick = () => {
      const progress = parseFloat(
        section.style.getPropertyValue("--lifeline-intro-progress") || "0",
      )
      const tip = progress * ol.offsetHeight

      while (next < entries.length && entries[next].offsetTop <= tip) {
        const el = targets[next]
        if (el) {
          el.classList.remove("opacity-0")
          el.classList.add("lifeline-marker-intro")
        }
        next++
      }

      if (next < entries.length) {
        frame = requestAnimationFrame(tick)
      }
    }
    frame = requestAnimationFrame(tick)

    return () => {
      cancelAnimationFrame(frame)
      section.removeEventListener("animationend", onAnimationEnd)
      targets.forEach((el) => {
        el?.classList.remove("opacity-0", "lifeline-marker-intro")
      })
    }
  }, [showIntro, revealOnScroll, sectionRef])

  const introStyle = {
    "--lifeline-labels-ms": `${intro.labelsDuration}ms`,
    "--lifeline-rail-ms": `${intro.railDuration}ms`,
  } as CSSProperties

  return (
    <article
      ref={sectionRef}
      aria-label={title}
      className={cn(
        "relative select-none px-6 pb-10 pt-4 [&_a]:cursor-pointer",
        !isLayoutReady && "invisible",
      )}
      style={showIntro ? introStyle : undefined}
    >
      <div className={cn(`${GRID_CLASS} mb-6 items-end`, showIntro && "lifeline-labels-intro")}>
        <p className="text-right text-[11px] font-medium uppercase leading-4 tracking-[0.08em] text-zinc-500 transition-colors duration-300 dark:text-zinc-600">
          Age
        </p>
        <div aria-hidden="true" />
        <p className="text-[11px] font-medium uppercase leading-5 tracking-[0.08em] text-zinc-500 transition-colors duration-300 dark:text-zinc-600">
          Years
        </p>
      </div>

      <div className="relative">
        <div
          aria-hidden="true"
          className="pointer-events-none absolute bottom-0 top-0 overflow-hidden -translate-x-1/2"
          style={{ left: RAIL_LEFT, width: 1 }}
        >
          <div
            className={cn(
              "h-full w-px border-l border-dashed border-zinc-300 transition-colors duration-300 dark:border-zinc-800",
              showIntro && "lifeline-rail-intro-vertical",
            )}
          />
        </div>

        <ol className="relative">
          {markers.map((marker, index) => (
            <LifelineVerticalEntry
              key={marker.id}
              ref={(node) => setEntryRef(index, node)}
              marker={marker}
              birthYear={birthYear}
              animateIntro={animateEntries}
              revealPending={showIntro && revealOnScroll}
              introDelay={intro.getMarkerDelay(index)}
              introDuration={intro.getMarkerFadeDuration(index)}
            />
          ))}
        </ol>
      </div>
    </article>
  )
}

"use client"

import { useLayoutEffect, useState } from "react"
import { cn } from "@/lib/utils"
import { LifelineDesktop } from "./lifeline-desktop"
import { LifelineFireworksProvider } from "./lifeline-fireworks"
import { LifelineVertical } from "./lifeline-vertical"
import { LIFELINE_MOBILE_BREAKPOINT } from "./lifeline-layout"
import type { LifelineProps } from "./types"

export function Lifeline(props: LifelineProps) {
  const [isMobile, setIsMobile] = useState<boolean | null>(null)

  useLayoutEffect(() => {
    // Matches Tailwind's md: breakpoint so JS and CSS can never disagree.
    const query = window.matchMedia(
      `(min-width: ${LIFELINE_MOBILE_BREAKPOINT}px)`,
    )
    const update = () => setIsMobile(!query.matches)

    update()
    query.addEventListener("change", update)
    return () => query.removeEventListener("change", update)
  }, [])

  if (isMobile === null) {
    return <div className="invisible h-full min-h-[50vh]" aria-hidden="true" />
  }

  if (isMobile) {
    return (
      <LifelineFireworksProvider>
        <div className="pt-5">
          <LifelineVertical {...props} />
        </div>
      </LifelineFireworksProvider>
    )
  }

  return (
    <LifelineFireworksProvider>
      <LifelineDesktop
        {...props}
        className={cn("pt-5", props.className)}
      />
    </LifelineFireworksProvider>
  )
}

import type { CompanyIconId } from "./company-icon"


export interface LifelineMentor {
  name: string
  role?: string
  color?: string
  photo?: string
}

export interface LifelineMetPerson {
  name: string
  photo?: string
}

export interface LifelineCompany {
  id: CompanyIconId
  name: string
}

export type LifelineEventSegment =
  | { type: "text"; value: string }
  | { type: "link"; value: string; href: string }

export interface LifelineEventImage {
  src: string
  alt: string
  /** Optional mp4/webm — hover shows this (muted, looping) with src as fallback. */
  video?: string
}

/**
 * An always-visible photo/video card that floats over the timeline,
 * anchored to its marker's position and scrolling with the track —
 * scattered, tilted, and draggable, like photos loose in a notebook.
 */
export interface LifelinePhoto extends LifelineEventImage {
  /** 0..1 across the marker's slot; defaults to a seeded scatter. */
  x?: number
  /** Pixels below the rail; defaults to a seeded scatter. */
  y?: number
  /** Degrees; defaults to a seeded tilt. */
  rotate?: number
  /** Card width in pixels. Default 180. */
  width?: number
}

export type LifelineEventEffect = "fireworks" | "fireworks-argentina"

/**
 * Object form lets an event carry a cursor-following hover image
 * and/or a click-triggered easter egg effect.
 */
export interface LifelineEventObject {
  text: string | LifelineEventSegment[]
  image?: LifelineEventImage
  effect?: LifelineEventEffect
}

export type LifelineEvent =
  | string
  | LifelineEventSegment[]
  | LifelineEventObject

export interface LifelineMarker {
  id: string
  /** Position on the numeric axis — a year, or any sequential unit (e.g. tournament day). */
  year: number
  /** Shown above the label; defaults to year - birthYear. Strings allowed for round tags etc. */
  age?: number | string
  /** Shown in place of the raw year — e.g. "Jun 16" on a day-based timeline. */
  label?: string
  events: LifelineEvent[]
  /** Small emblems (team shields etc.) rendered above the events. */
  badges?: { src: string; alt: string }[]
  /** Floating media cards anchored to this marker's stretch of the timeline. */
  photos?: LifelinePhoto[]
  companies?: LifelineCompany[]
  mentors?: LifelineMentor[]
  met?: LifelineMetPerson[]
}

/**
 * A legend entry maps one of the two people slots to a subject-appropriate
 * label — "Mentors" for a person, "Presidents" for a nation.
 */
export interface LifelineLegendItem {
  type: "mentor" | "met"
  label: string
}

export interface LifelineProps {
  markers: LifelineMarker[]
  birthYear: number
  className?: string
  title?: string
}

"use client"

import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import {
  getTransitionMarkerFadeDuration,
  LIFELINE_FAST_MARKER_FADE_MS,
  timeAtTrackProgress,
  trackProgressAtTime,
} from "./lifeline-intro-timing"

/** Tweak these */
export const LIFELINE_LABELS_MS = 600
export const LIFELINE_RAIL_MS = 3200
/**
 * Track length (px on desktop, tall lifelines on mobile) the base rail
 * duration was tuned for — roughly a 40-year personal lifeline. Longer
 * tracks slow the sweep sublinearly so dense timelines stay readable,
 * capped so a 250-year nation doesn't become a screensaver.
 */
export const LIFELINE_REFERENCE_TRACK = 9000
export const LIFELINE_RAIL_MAX_MS = 7200
export const LIFELINE_RAIL_SCALE_POWER = 0.45
/**
 * Keep fade stretching subtle — long fades lag behind the sweeping
 * line and read as out of sync.
 */
export const LIFELINE_FADE_SCALE_MAX = 1.5

export function useLifelineIntro(markerWidths: number[]) {
  // Skip straight to the settled end state for users who prefer reduced motion.
  const [shouldPlay] = useState(
    () =>
      typeof window === "undefined" ||
      !window.matchMedia("(prefers-reduced-motion: reduce)").matches,
  )
  const [isPlaying, setIsPlaying] = useState(true)
  const [isComplete, setIsComplete] = useState(false)
  const introTimeoutRef = useRef(0)

  const totalMarkersWidth = useMemo(
    () => markerWidths.reduce((sum, width) => sum + width, 0),
    [markerWidths],
  )

  const railDuration = useMemo(() => {
    if (totalMarkersWidth <= LIFELINE_REFERENCE_TRACK) return LIFELINE_RAIL_MS

    const scale = Math.pow(
      totalMarkersWidth / LIFELINE_REFERENCE_TRACK,
      LIFELINE_RAIL_SCALE_POWER,
    )
    return Math.min(LIFELINE_RAIL_MAX_MS, Math.round(LIFELINE_RAIL_MS * scale))
  }, [totalMarkersWidth])

  // Stretch each marker's fade with the sweep so dense timelines bloom
  // in a trailing wave instead of flickering past.
  const fadeScale = Math.min(
    LIFELINE_FADE_SCALE_MAX,
    railDuration / LIFELINE_RAIL_MS,
  )

  const introDuration =
    railDuration + Math.round(LIFELINE_FAST_MARKER_FADE_MS * fadeScale)

  const getTrackProgressAtTime = useCallback(
    (elapsedMs: number) => {
      if (!shouldPlay || totalMarkersWidth <= 0) {
        return Math.min(elapsedMs / railDuration, 1)
      }

      return trackProgressAtTime(elapsedMs, markerWidths, railDuration)
    },
    [markerWidths, railDuration, shouldPlay, totalMarkersWidth],
  )

  const getMarkerDelay = useCallback(
    (index: number) => {
      if (!shouldPlay || totalMarkersWidth <= 0) return 0

      const offset = markerWidths
        .slice(0, index)
        .reduce((sum, width) => sum + width, 0)

      return timeAtTrackProgress(
        offset / totalMarkersWidth,
        markerWidths,
        railDuration,
      )
    },
    [markerWidths, railDuration, shouldPlay, totalMarkersWidth],
  )

  const getMarkerFadeDuration = useCallback(
    (index: number) => {
      return Math.round(getTransitionMarkerFadeDuration(index) * fadeScale)
    },
    [fadeScale],
  )

  const completeIntro = useCallback(() => {
    setIsComplete(true)
  }, [])

  const startIntroTimer = useCallback(() => {
    window.clearTimeout(introTimeoutRef.current)
    setIsPlaying(true)
    setIsComplete(false)

    introTimeoutRef.current = window.setTimeout(() => {
      setIsPlaying(false)
    }, introDuration)
  }, [introDuration])

  useEffect(() => {
    return () => window.clearTimeout(introTimeoutRef.current)
  }, [])

  return {
    shouldPlay,
    isPlaying,
    isComplete,
    labelsDuration: LIFELINE_LABELS_MS,
    railDuration,
    getTrackProgressAtTime,
    getMarkerDelay,
    getMarkerFadeDuration,
    startIntroTimer,
    completeIntro,
  }
}

"use client"

import { useCallback, useEffect, useLayoutEffect, useRef, useState } from "react"
import {
  LIFELINE_STICKY_LEFT,
  LIFELINE_STICKY_SHIELD_WIDTH,
} from "./lifeline-labels"
import { clamp } from "./lifeline-utils"

const NAV_HEIGHT = 64
const FOOTER_HEIGHT = 64
const FADE_ZONE = 200
const FADE_ZONE_COARSE = 72
const LEFT_EXIT_FADE_ZONE = 400
const LEFT_EXIT_FADE_ZONE_COARSE = 160
const WHEEL_SPEED = 1.4
const WHEEL_VELOCITY_FRAME_MS = 16.67
const WHEEL_MOMENTUM_BLEND = 0.65
const DRAG_SPEED = 1
const TOUCH_DRAG_SPEED = 1.15
const TOUCH_GESTURE_LOCK_PX = 8
const NAV_HORIZONTAL_PADDING = 24
const MOMENTUM_FRICTION = 0.94
const MOMENTUM_MIN_VELOCITY = 0.025
const MOMENTUM_MIN_START = 0.08

function normalizeWheelDelta(event: WheelEvent) {
  let delta = Math.abs(event.deltaX) > Math.abs(event.deltaY)
    ? event.deltaX
    : event.deltaY

  if (event.deltaMode === 1) delta *= 16
  if (event.deltaMode === 2) delta *= window.innerHeight

  return delta
}

function isInteractiveTarget(target: EventTarget | null) {
  // Pointer capture during drag retargets clicks to the section, so
  // anything clickable must opt out of drag-start here.
  return (
    target instanceof Element &&
    Boolean(target.closest("a, button, [data-lifeline-interactive]"))
  )
}

function isInStage(clientY: number, isCoarsePointer: boolean) {
  if (isCoarsePointer) return clientY >= NAV_HEIGHT

  return (
    clientY >= NAV_HEIGHT &&
    clientY <= window.innerHeight - FOOTER_HEIGHT
  )
}

interface LifelineScrollOptions {
  isCoarsePointer?: boolean
  introLocked?: boolean
  introAnimating?: boolean
  introSkipped?: boolean
  introRailMs?: number
  introGetTrackProgress?: (elapsedMs: number) => number
  onIntroSettleComplete?: () => void
  onIntroScrollStart?: () => void
}

export function useLifelineScroll(
  markerCount: number,
  options: LifelineScrollOptions = {},
) {
  const sectionRef = useRef<HTMLDivElement>(null)
  const trackRef = useRef<HTMLDivElement>(null)
  const labelsRef = useRef<HTMLDivElement>(null)
  const markerRefs = useRef<(HTMLDivElement | null)[]>([])
  const maxTranslate = useRef(0)
  const startInset = useRef(24)
  const endInset = useRef(0)
  const translatePx = useRef(0)
  const initialized = useRef(false)
  const dragging = useRef(false)
  const gestureAxis = useRef<"x" | "y" | null>(null)
  const gestureStart = useRef({ x: 0, y: 0 })
  const dragOrigin = useRef({ x: 0, translate: 0 })
  const dragVelocity = useRef(0)
  const lastPointerSample = useRef({ x: 0, t: 0 })
  const activePointerId = useRef<number | null>(null)
  const isCoarsePointerRef = useRef(options.isCoarsePointer ?? false)
  const momentumId = useRef(0)
  const settleId = useRef(0)
  const introLockedRef = useRef(options.introLocked ?? false)
  const introAnimatingRef = useRef(options.introAnimating ?? false)
  const introSkippedRef = useRef(options.introSkipped ?? false)
  const onIntroSettleCompleteRef = useRef(options.onIntroSettleComplete)
  const onIntroScrollStartRef = useRef(options.onIntroScrollStart)
  const settlingRef = useRef(false)
  const introWasAnimatingRef = useRef(false)
  const introScrollId = useRef(0)
  const introScrollStart = useRef(0)
  const introStartedRef = useRef(false)
  const introGetTrackProgressRef = useRef(options.introGetTrackProgress)
  const applyTranslateRef = useRef<(value: number) => void>(() => {})
  const scheduleMeasureRef = useRef<() => void>(() => {})
  const [isLayoutReady, setIsLayoutReady] = useState(false)

  isCoarsePointerRef.current = options.isCoarsePointer ?? false
  introLockedRef.current = options.introLocked ?? false
  introAnimatingRef.current = options.introAnimating ?? false
  introSkippedRef.current = options.introSkipped ?? false
  onIntroSettleCompleteRef.current = options.onIntroSettleComplete
  onIntroScrollStartRef.current = options.onIntroScrollStart
  introGetTrackProgressRef.current = options.introGetTrackProgress

  const setMarkerRef = useCallback(
    (index: number, node: HTMLDivElement | null) => {
      markerRefs.current[index] = node

      if (index === markerCount - 1 && node) {
        scheduleMeasureRef.current()
      }
    },
    [markerCount],
  )

  const getLabelViewportLeft = useCallback((translate: number) => {
    const section = sectionRef.current
    if (!section) return { isSticky: false, labelLeft: 0 }

    const stageLeft = section.getBoundingClientRect().left
    const naturalLeft = stageLeft + startInset.current - translate
    const isSticky = naturalLeft <= LIFELINE_STICKY_LEFT

    return {
      isSticky,
      labelLeft: isSticky ? LIFELINE_STICKY_LEFT : naturalLeft,
    }
  }, [])

  const applyLabelSticky = useCallback(
    (translate: number) => {
      const section = sectionRef.current
      const labels = labelsRef.current
      const { isSticky, labelLeft } = getLabelViewportLeft(translate)

      if (!section || !labels) return { isSticky, labelLeft }

      if (isSticky) {
        const stageLeft = section.getBoundingClientRect().left
        const labelExtra =
          LIFELINE_STICKY_LEFT - stageLeft - startInset.current + translate
        labels.style.transform = `translate3d(${labelExtra}px, 0, 0)`
        labels.classList.add("is-pinned")
      } else {
        labels.style.transform = ""
        labels.classList.remove("is-pinned")
      }

      return { isSticky, labelLeft }
    },
    [getLabelViewportLeft],
  )

  const isScrollLocked = useCallback(() => {
    return (
      (introLockedRef.current && introStartedRef.current) ||
      settlingRef.current
    )
  }, [])

  const updateFades = useCallback(() => {
    if (settlingRef.current) return

    const width = window.innerWidth
    const isCoarse = isCoarsePointerRef.current
    const fadeZone = isCoarse ? FADE_ZONE_COARSE : FADE_ZONE
    const leftFadeZone = isCoarse
      ? LEFT_EXIT_FADE_ZONE_COARSE
      : LEFT_EXIT_FADE_ZONE

    markerRefs.current.forEach((marker) => {
      if (!marker) return

      const rect = marker.getBoundingClientRect()
      const center = rect.left + rect.width / 2

      let opacity = 1

      // Fade a marker out only as scrubbing carries it left of where
      // it rests at translate 0 — the first markers naturally live
      // inside the fade zone and must not open dimmed.
      const naturalLeft = rect.left + translatePx.current
      const restLeft = Math.min(naturalLeft, leftFadeZone)
      if (rect.left < restLeft) {
        opacity = rect.left <= 0 ? 0 : rect.left / restLeft
      }

      if (center > width - fadeZone) {
        opacity = Math.min(opacity, (width - center) / fadeZone)
      }

      if (isCoarse) {
        const readableLeft = LIFELINE_STICKY_SHIELD_WIDTH
        const readableRight = width - 12
        const visibleWidth =
          Math.min(rect.right, readableRight) - Math.max(rect.left, readableLeft)
        const visibility = rect.width > 0 ? visibleWidth / rect.width : 0

        if (visibility >= 0.5) {
          opacity = 1
        }
      }

      marker.style.opacity = String(clamp(opacity, 0, 1))
    })
  }, [])

  const applyTranslate = useCallback(
    (value: number) => {
      const max = maxTranslate.current
      const next = clamp(value, 0, max)
      translatePx.current = next

      if (trackRef.current) {
        trackRef.current.style.transform = `translate3d(${startInset.current - next}px, 0, 0)`
      }

      applyLabelSticky(next)
      updateFades()
    },
    [applyLabelSticky, updateFades],
  )

  applyTranslateRef.current = applyTranslate

  const measureLayout = useCallback(() => {
    const track = trackRef.current
    const section = sectionRef.current
    if (!track || !section) return 0

    const stageRect = section.getBoundingClientRect()
    const navLogo = document.querySelector("[data-site-nav-logo]")
    const navInner = document.querySelector("[data-site-nav-inner]")

    if (navLogo) {
      const logoRect = navLogo.getBoundingClientRect()
      startInset.current = logoRect.left - stageRect.left
    }

    if (navInner) {
      const navRect = navInner.getBoundingClientRect()
      endInset.current =
        navRect.right - stageRect.left - NAV_HORIZONTAL_PADDING
    } else {
      // No host nav to align with ([data-site-nav-inner] missing) —
      // end the track at the stage's own right edge instead.
      endInset.current = stageRect.width - NAV_HORIZONTAL_PADDING
    }

    const lastMarker = markerRefs.current[markerCount - 1]
    const lastMarkerRight = lastMarker
      ? LIFELINE_STICKY_SHIELD_WIDTH +
        lastMarker.offsetLeft +
        lastMarker.offsetWidth
      : track.scrollWidth

    const max = Math.max(
      0,
      startInset.current + lastMarkerRight - endInset.current,
    )
    maxTranslate.current = max

    return max
  }, [markerCount])

  useLayoutEffect(() => {
    markerRefs.current.length = markerCount
  }, [markerCount])

  useLayoutEffect(() => {
    const max = measureLayout()
    if (max <= 0) return

    if (!initialized.current) {
      translatePx.current = introSkippedRef.current ? max : 0
      initialized.current = true
    }

    applyTranslate(translatePx.current)
    setIsLayoutReady(true)
    // Sync initial position once before first paint; resize uses measure().
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  useEffect(() => {
    if (!isLayoutReady) return
    if (options.introSkipped || !options.introAnimating) {
      cancelAnimationFrame(introScrollId.current)
      introScrollId.current = 0
      introStartedRef.current = false
      return
    }

    introWasAnimatingRef.current = true
    const railMs = options.introRailMs ?? 3200

    const step = (now: number) => {
      const max = maxTranslate.current

      if (max <= 0) {
        introScrollId.current = requestAnimationFrame(step)
        return
      }

      if (!introStartedRef.current) {
        introStartedRef.current = true
        introScrollStart.current = now
        onIntroScrollStartRef.current?.()
        sectionRef.current?.style.setProperty("--lifeline-intro-progress", "0")
        applyTranslateRef.current(0)
      }

      const elapsed = now - introScrollStart.current
      const progress = introGetTrackProgressRef.current
        ? clamp(introGetTrackProgressRef.current(elapsed), 0, 1)
        : clamp(elapsed / railMs, 0, 1)

      sectionRef.current?.style.setProperty(
        "--lifeline-intro-progress",
        String(progress),
      )
      applyTranslateRef.current(progress * max)

      if (progress < 1) {
        introScrollId.current = requestAnimationFrame(step)
        return
      }

      sectionRef.current?.style.setProperty("--lifeline-intro-progress", "1")
      applyTranslateRef.current(max)
      introScrollId.current = 0
    }

    introScrollId.current = requestAnimationFrame(step)

    return () => {
      cancelAnimationFrame(introScrollId.current)
      introScrollId.current = 0
      introStartedRef.current = false
    }
  }, [
    isLayoutReady,
    options.introAnimating,
    options.introRailMs,
    options.introSkipped,
  ])

  useEffect(() => {
    if (options.introSkipped) return

    if (options.introAnimating) return

    if (!introWasAnimatingRef.current) return
    introWasAnimatingRef.current = false

    sectionRef.current?.style.removeProperty("--lifeline-intro-progress")
    markerRefs.current.forEach((marker) => {
      if (marker) marker.style.opacity = ""
    })
    updateFades()
    onIntroSettleCompleteRef.current?.()
  }, [
    options.introAnimating,
    options.introSkipped,
    updateFades,
  ])

  useEffect(() => {
    const html = document.documentElement
    const body = document.body

    html.classList.add("lifeline-scroll")
    const previousHtmlOverflow = html.style.overflow
    const previousBodyOverflow = body.style.overflow
    html.style.overflow = "hidden"
    body.style.overflow = "hidden"
    window.scrollTo(0, 0)

    return () => {
      html.classList.remove("lifeline-scroll")
      html.style.overflow = previousHtmlOverflow
      body.style.overflow = previousBodyOverflow
      initialized.current = false
    }
  }, [])

  useEffect(() => {
    const section = sectionRef.current
    if (!section) return

    let frameId = 0
    let resizeObserver: ResizeObserver | null = null

    const stopMomentum = () => {
      cancelAnimationFrame(momentumId.current)
      momentumId.current = 0
    }

    const startMomentum = () => {
      if (Math.abs(dragVelocity.current) < MOMENTUM_MIN_START) return

      stopMomentum()
      let lastFrameTime = performance.now()

      const step = (now: number) => {
        const dt = Math.min(now - lastFrameTime, 32)
        lastFrameTime = now

        const velocity = dragVelocity.current
        if (Math.abs(velocity) < MOMENTUM_MIN_VELOCITY) {
          dragVelocity.current = 0
          momentumId.current = 0
          return
        }

        const max = maxTranslate.current
        const next = clamp(translatePx.current + velocity * dt, 0, max)

        if (next !== translatePx.current) {
          applyTranslate(next)
        }

        if (next <= 0 || next >= max) {
          dragVelocity.current = 0
          momentumId.current = 0
          return
        }

        dragVelocity.current =
          velocity * Math.pow(MOMENTUM_FRICTION, dt / 16.67)
        momentumId.current = requestAnimationFrame(step)
      }

      momentumId.current = requestAnimationFrame(step)
    }

    const measure = () => {
      const max = measureLayout()
      if (max <= 0) return

      translatePx.current = clamp(translatePx.current, 0, max)

      // During intro scroll, the rAF loop owns translate — only refresh bounds.
      if (!(introAnimatingRef.current && introStartedRef.current)) {
        applyTranslate(translatePx.current)
      }

      setIsLayoutReady(true)
    }

    const scheduleMeasure = () => {
      cancelAnimationFrame(frameId)
      frameId = requestAnimationFrame(measure)
    }

    scheduleMeasureRef.current = scheduleMeasure

    scheduleMeasure()
    frameId = requestAnimationFrame(() => {
      measure()
      requestAnimationFrame(measure)
    })

    resizeObserver = new ResizeObserver(scheduleMeasure)
    if (trackRef.current) resizeObserver.observe(trackRef.current)

    window.addEventListener("resize", scheduleMeasure)

    const onWheel = (event: WheelEvent) => {
      if (!isInStage(event.clientY, isCoarsePointerRef.current)) return
      if (isScrollLocked()) return

      if (maxTranslate.current <= 0) {
        scheduleMeasure()
        return
      }

      event.preventDefault()

      const delta = normalizeWheelDelta(event)
      const movement = -delta * WHEEL_SPEED

      applyTranslate(translatePx.current + movement)

      const impulse = (movement / WHEEL_VELOCITY_FRAME_MS) * 0.35
      dragVelocity.current =
        dragVelocity.current * (1 - WHEEL_MOMENTUM_BLEND) +
        impulse * WHEEL_MOMENTUM_BLEND

      if (momentumId.current === 0) {
        startMomentum()
      }
    }

    const beginDrag = (event: PointerEvent) => {
      stopMomentum()
      dragVelocity.current = 0
      dragging.current = true
      activePointerId.current = event.pointerId
      dragOrigin.current = { x: event.clientX, translate: translatePx.current }
      lastPointerSample.current = {
        x: event.clientX,
        t: performance.now(),
      }

      if (section.setPointerCapture) {
        section.setPointerCapture(event.pointerId)
      }

      section.style.cursor = "grabbing"
      section.style.touchAction = "none"
    }

    const onPointerDown = (event: PointerEvent) => {
      if (!isInStage(event.clientY, isCoarsePointerRef.current)) return
      if (isScrollLocked()) return
      if (isInteractiveTarget(event.target)) return
      if (maxTranslate.current <= 0) return
      if (activePointerId.current !== null) return

      gestureAxis.current = null
      gestureStart.current = { x: event.clientX, y: event.clientY }

      if (event.pointerType === "touch") {
        activePointerId.current = event.pointerId
        return
      }

      beginDrag(event)
    }

    const onPointerMove = (event: PointerEvent) => {
      if (activePointerId.current !== null && event.pointerId !== activePointerId.current) {
        return
      }

      if (!dragging.current && event.pointerType === "touch") {
        const deltaX = event.clientX - gestureStart.current.x
        const deltaY = event.clientY - gestureStart.current.y

        if (gestureAxis.current === null) {
          if (
            Math.abs(deltaX) < TOUCH_GESTURE_LOCK_PX &&
            Math.abs(deltaY) < TOUCH_GESTURE_LOCK_PX
          ) {
            return
          }

          gestureAxis.current =
            Math.abs(deltaX) >= Math.abs(deltaY) ? "x" : "y"

          if (gestureAxis.current === "y") {
            activePointerId.current = null
            return
          }

          beginDrag(event)
        }
      }

      if (!dragging.current) return

      if (event.pointerType === "touch") {
        event.preventDefault()
      }

      const now = performance.now()
      const sample = lastPointerSample.current
      const elapsed = now - sample.t
      const dragSpeed = event.pointerType === "touch" ? TOUCH_DRAG_SPEED : DRAG_SPEED

      if (elapsed > 0 && elapsed < 80) {
        const instantVelocity =
          (-(event.clientX - sample.x) / elapsed) * dragSpeed
        dragVelocity.current =
          instantVelocity * 0.65 + dragVelocity.current * 0.35
      }

      lastPointerSample.current = { x: event.clientX, t: now }

      const deltaX = event.clientX - dragOrigin.current.x
      applyTranslate(dragOrigin.current.translate - deltaX * dragSpeed)
    }

    const endDrag = (event: PointerEvent) => {
      if (activePointerId.current !== null && event.pointerId !== activePointerId.current) {
        return
      }

      const wasDragging = dragging.current

      dragging.current = false
      gestureAxis.current = null
      activePointerId.current = null

      if (section.hasPointerCapture(event.pointerId)) {
        section.releasePointerCapture(event.pointerId)
      }

      section.style.cursor = ""
      section.style.touchAction = ""

      if (wasDragging) {
        startMomentum()
      }
    }

    const onKeyDown = (event: KeyboardEvent) => {
      if (maxTranslate.current <= 0) return
      if (isScrollLocked()) return

      stopMomentum()
      dragVelocity.current = 0

      if (event.key === "ArrowLeft" || event.key === "ArrowUp") {
        event.preventDefault()
        applyTranslate(translatePx.current - maxTranslate.current * 0.05)
      }

      if (event.key === "ArrowRight" || event.key === "ArrowDown") {
        event.preventDefault()
        applyTranslate(translatePx.current + maxTranslate.current * 0.05)
      }
    }

    window.addEventListener("wheel", onWheel, { passive: false })
    section.addEventListener("pointerdown", onPointerDown)
    section.addEventListener("pointermove", onPointerMove, { passive: false })
    section.addEventListener("pointerup", endDrag)
    section.addEventListener("pointercancel", endDrag)
    window.addEventListener("keydown", onKeyDown)

    return () => {
      cancelAnimationFrame(frameId)
      stopMomentum()
      cancelAnimationFrame(settleId.current)
      settlingRef.current = false
      resizeObserver?.disconnect()
      window.removeEventListener("resize", scheduleMeasure)
      window.removeEventListener("wheel", onWheel)
      section.removeEventListener("pointerdown", onPointerDown)
      section.removeEventListener("pointermove", onPointerMove)
      section.removeEventListener("pointerup", endDrag)
      section.removeEventListener("pointercancel", endDrag)
      window.removeEventListener("keydown", onKeyDown)
      dragging.current = false
      gestureAxis.current = null
      activePointerId.current = null
      section.style.cursor = ""
      section.style.touchAction = ""
    }
  }, [applyTranslate, isScrollLocked, markerCount, measureLayout])

  return { sectionRef, trackRef, labelsRef, setMarkerRef, isLayoutReady }
}

"use client"

import { useCallback, useEffect, useLayoutEffect, useRef, useState } from "react"
import { clamp } from "./lifeline-utils"

function getScrollParent(element: HTMLElement | null): HTMLElement | null {
  let node = element?.parentElement ?? null

  while (node) {
    const { overflowY } = window.getComputedStyle(node)
    if (overflowY === "auto" || overflowY === "scroll" || overflowY === "overlay") {
      return node
    }
    node = node.parentElement
  }

  return null
}

interface LifelineVerticalScrollOptions {
  introLocked?: boolean
  introAnimating?: boolean
  introSkipped?: boolean
  introRailMs?: number
  introGetTrackProgress?: (elapsedMs: number) => number
  onIntroSettleComplete?: () => void
  onIntroScrollStart?: () => void
}

export function useLifelineVerticalScroll(
  markerCount: number,
  options: LifelineVerticalScrollOptions = {},
) {
  const sectionRef = useRef<HTMLElement>(null)
  const entryRefs = useRef<(HTMLLIElement | null)[]>([])
  const maxScrollRef = useRef(0)
  const scrollParentRef = useRef<HTMLElement | null>(null)
  const initialized = useRef(false)
  const introLockedRef = useRef(options.introLocked ?? false)
  const introAnimatingRef = useRef(options.introAnimating ?? false)
  const introSkippedRef = useRef(options.introSkipped ?? false)
  const onIntroSettleCompleteRef = useRef(options.onIntroSettleComplete)
  const onIntroScrollStartRef = useRef(options.onIntroScrollStart)
  const introGetTrackProgressRef = useRef(options.introGetTrackProgress)
  const introStartedRef = useRef(false)
  const introScrollId = useRef(0)
  const introScrollStart = useRef(0)
  const introWasAnimatingRef = useRef(false)
  const scheduleMeasureRef = useRef<() => void>(() => {})
  const [isLayoutReady, setIsLayoutReady] = useState(false)

  introLockedRef.current = options.introLocked ?? false
  introAnimatingRef.current = options.introAnimating ?? false
  introSkippedRef.current = options.introSkipped ?? false
  onIntroSettleCompleteRef.current = options.onIntroSettleComplete
  onIntroScrollStartRef.current = options.onIntroScrollStart
  introGetTrackProgressRef.current = options.introGetTrackProgress

  const setEntryRef = useCallback((index: number, node: HTMLLIElement | null) => {
    entryRefs.current[index] = node

    if (index === markerCount - 1 && node) {
      scheduleMeasureRef.current()
    }
  }, [markerCount])

  const applyScroll = useCallback((value: number) => {
    const scrollParent = scrollParentRef.current
    if (!scrollParent) return

    scrollParent.scrollTop = clamp(value, 0, maxScrollRef.current)
  }, [])

  const measureLayout = useCallback(() => {
    const section = sectionRef.current
    if (!section) return 0

    const scrollParent = getScrollParent(section)
    scrollParentRef.current = scrollParent

    if (!scrollParent) return 0

    const heights = entryRefs.current.map((entry) => entry?.offsetHeight ?? 0)
    if (heights.length < markerCount || heights.some((height) => height <= 0)) {
      return 0
    }

    const max = Math.max(0, scrollParent.scrollHeight - scrollParent.clientHeight)
    maxScrollRef.current = max

    return max
  }, [markerCount])

  useLayoutEffect(() => {
    entryRefs.current.length = markerCount
  }, [markerCount])

  useLayoutEffect(() => {
    const max = measureLayout()

    const scrollParent = scrollParentRef.current
    if (!scrollParent) return

    if (!initialized.current) {
      scrollParent.scrollTop = introSkippedRef.current ? max : 0
      initialized.current = true
    }

    setIsLayoutReady(entryRefs.current.every((entry) => Boolean(entry)))
    // Sync initial position once before first paint; resize uses measure().
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  useEffect(() => {
    if (!isLayoutReady) return
    if (options.introSkipped || !options.introAnimating) {
      cancelAnimationFrame(introScrollId.current)
      introScrollId.current = 0
      introStartedRef.current = false
      return
    }

    introWasAnimatingRef.current = true
    const railMs = options.introRailMs ?? 3200

    const step = (now: number) => {
      const max = maxScrollRef.current

      if (!introStartedRef.current) {
        introStartedRef.current = true
        introScrollStart.current = now
        onIntroScrollStartRef.current?.()
        sectionRef.current?.style.setProperty("--lifeline-intro-progress", "0")
        if (max > 0) applyScroll(0)
      }

      const elapsed = now - introScrollStart.current
      const progress = introGetTrackProgressRef.current
        ? clamp(introGetTrackProgressRef.current(elapsed), 0, 1)
        : clamp(elapsed / railMs, 0, 1)

      sectionRef.current?.style.setProperty(
        "--lifeline-intro-progress",
        String(progress),
      )

      if (max > 0) {
        applyScroll(progress * max)
      }

      if (progress < 1) {
        introScrollId.current = requestAnimationFrame(step)
        return
      }

      sectionRef.current?.style.setProperty("--lifeline-intro-progress", "1")
      if (max > 0) applyScroll(max)
      introScrollId.current = 0
    }

    introScrollId.current = requestAnimationFrame(step)

    return () => {
      cancelAnimationFrame(introScrollId.current)
      introScrollId.current = 0
      introStartedRef.current = false
    }
  }, [
    applyScroll,
    isLayoutReady,
    options.introAnimating,
    options.introRailMs,
    options.introSkipped,
  ])

  useEffect(() => {
    if (options.introSkipped) return
    if (options.introAnimating) return
    if (!introWasAnimatingRef.current) return

    introWasAnimatingRef.current = false
    sectionRef.current?.style.removeProperty("--lifeline-intro-progress")
    onIntroSettleCompleteRef.current?.()
  }, [options.introAnimating, options.introSkipped])

  useEffect(() => {
    const section = sectionRef.current
    if (!section) return

    let frameId = 0
    let resizeObserver: ResizeObserver | null = null

    const measure = () => {
      measureLayout()

      const scrollParent = scrollParentRef.current
      if (!scrollParent) return

      if (!(introAnimatingRef.current && introStartedRef.current)) {
        scrollParent.scrollTop = clamp(
          scrollParent.scrollTop,
          0,
          maxScrollRef.current,
        )
      }

      setIsLayoutReady(
        entryRefs.current.length === markerCount &&
          entryRefs.current.every((entry) => Boolean(entry)),
      )
    }

    const scheduleMeasure = () => {
      cancelAnimationFrame(frameId)
      frameId = requestAnimationFrame(measure)
    }

    scheduleMeasureRef.current = scheduleMeasure

    scheduleMeasure()
    frameId = requestAnimationFrame(() => {
      measure()
      requestAnimationFrame(measure)
    })

    resizeObserver = new ResizeObserver(scheduleMeasure)
    resizeObserver.observe(section)

    window.addEventListener("resize", scheduleMeasure)

    const isScrollLocked = () =>
      introLockedRef.current && introStartedRef.current

    const preventScroll = (event: Event) => {
      if (!isScrollLocked()) return
      event.preventDefault()
    }

    const scrollParent = getScrollParent(section)
    scrollParentRef.current = scrollParent

    scrollParent?.addEventListener("wheel", preventScroll, { passive: false })
    scrollParent?.addEventListener("touchmove", preventScroll, { passive: false })

    return () => {
      cancelAnimationFrame(frameId)
      resizeObserver?.disconnect()
      window.removeEventListener("resize", scheduleMeasure)
      scrollParent?.removeEventListener("wheel", preventScroll)
      scrollParent?.removeEventListener("touchmove", preventScroll)
      initialized.current = false
    }
  }, [markerCount, measureLayout])

  return {
    sectionRef,
    setEntryRef,
    isLayoutReady,
  }
}

import type {
  LifelineEvent,
  LifelineLegendItem,
  LifelineMarker,
} from "@/components/lifeline/types"

export const LIFELINE_CURRENT_YEAR = 2026

export type LifelineMilestone = Omit<LifelineMarker, "year">
export type LifelineMilestones = Record<number, LifelineMilestone>

export interface LifelineRecord {
  slug: string
  name: string
  birthYear: number
  /** Last year on the timeline. Omit for living people. */
  endYear?: number
  description: string
  /** People-legend labels; defaults to Mentors / Met in person. */
  legend?: LifelineLegendItem[]
  markers: LifelineMarker[]
}

interface DefineLifelineInput {
  slug: string
  name: string
  birthYear: number
  endYear?: number
  description: string
  legend?: LifelineLegendItem[]
  milestones: LifelineMilestones
}

/**
 * Translated event texts keyed by year, aligned by index with the
 * source milestone's events. Only the text is swapped — images,
 * effects, mentors, and structure stay single-sourced.
 */
export type LifelineTextOverrides = Record<number, string[]>

export function localizeLifelineMarkers(
  markers: LifelineMarker[],
  texts: LifelineTextOverrides,
): LifelineMarker[] {
  return markers.map((marker) => {
    const translated = texts[marker.year]
    if (!translated) return marker

    const events: LifelineEvent[] = marker.events.map((event, index) => {
      const text = translated[index]
      if (text === undefined) return event
      if (typeof event === "string") return text
      if (Array.isArray(event)) return event
      return { ...event, text }
    })

    return { ...marker, events }
  })
}

export function defineLifeline(input: DefineLifelineInput): LifelineRecord {
  const { milestones, ...record } = input
  const lastYear = input.endYear ?? LIFELINE_CURRENT_YEAR
  const markers: LifelineMarker[] = []

  for (let year = input.birthYear; year <= lastYear; year++) {
    const milestone = milestones[year]

    markers.push(
      milestone
        ? { year, ...milestone }
        : { id: `year-${year}`, year, events: [] },
    )
  }

  return { ...record, markers }
}

